mapper.select:
SELECT wa.id, wa.risk_level as riskLevel, wa.warning_type as warningType, wa.content, wa.risk_score as riskScore, wa.status, wa.process_result as processResult, wa.related_user_name as relatedUserName, wa.create_time as createTime, wa.processed_at as processedAt FROM warning_alert wa WHERE wa.deleted = 0
AND (wa.content LIKE CONCAT('%', #{keyword}, '%') OR wa.related_user_name LIKE CONCAT('%', #{keyword}, '%'))
AND wa.risk_level = #{riskLevel}
AND wa.warning_type = #{warningType}
AND wa.status = #{status}
ORDER BY wa.risk_level ASC, wa.create_time DESC
